type Option = { value: string; label: string; description?: string };

const surface = 'rounded-2xl border border-boh-border-light bg-boh-surface-light shadow-sm dark:border-boh-border dark:bg-boh-surface';
const input = 'h-10 w-full rounded-lg border border-boh-border-light bg-white px-3 text-sm font-normal text-boh-text-light outline-none transition focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/15 dark:border-boh-border dark:bg-boh-bg dark:text-boh-text';
const textarea = 'min-h-24 w-full resize-y rounded-lg border border-boh-border-light bg-white px-3 py-2 text-sm font-normal text-boh-text-light outline-none transition focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/15 dark:border-boh-border dark:bg-boh-bg dark:text-boh-text';
const secondaryButton = 'inline-flex h-9 items-center justify-center gap-2 rounded-lg border border-boh-border-light bg-white px-3 text-sm font-medium text-boh-text-light transition hover:bg-boh-bg-light disabled:cursor-not-allowed disabled:opacity-50 dark:border-boh-border dark:bg-boh-bg dark:text-boh-text dark:hover:bg-boh-surface';
const primaryButton = 'inline-flex h-9 items-center justify-center gap-2 rounded-lg bg-emerald-600 px-3 text-sm font-semibold text-white transition hover:bg-emerald-700 disabled:cursor-not-allowed disabled:opacity-50';

function formatDate(value: string | null | undefined) {
  if (!value) return 'Not yet';
  return new Intl.DateTimeFormat(undefined, { dateStyle: 'medium', timeStyle: 'short' }).format(new Date(value));
}

function friendly(value: string) {
  return value.replaceAll('_', ' ').replace(/\b\w/g, (letter) => letter.toUpperCase());
}

function StatusBadge({ value }: { value: string }) {
  const positive = ['configured', 'active', 'ready', 'succeeded', 'valid', 'synced'].includes(value);
  const negative = ['failed', 'error', 'revoked', 'invalid', 'blocked', 'needs_attention'].includes(value);
  return <span className={`inline-flex whitespace-nowrap rounded-full px-2 py-0.5 text-xs font-medium ${positive ? 'bg-emerald-500/10 text-emerald-700 dark:text-emerald-300' : negative ? 'bg-red-500/10 text-red-700 dark:text-red-300' : 'bg-slate-500/10 text-slate-600 dark:text-slate-300'}`}>{friendly(value)}</span>;
}

function Picker({ label, value, options, onChange, placeholder = 'Choose one' }: { label: string; value: string; options: Option[]; onChange: (value: string) => void; placeholder?: string }) {
  const [open, setOpen] = useState(false);
  const selected = options.find((option) => option.value === value);
  return <label className="relative block text-sm font-medium text-boh-text-light dark:text-boh-text">
    <span className="mb-1.5 block">{label}</span>
    <button type="button" aria-haspopup="listbox" aria-expanded={open} onClick={() => setOpen(!open)} className={`${input} flex items-center justify-between text-left font-normal`}>
      <span className={selected ? '' : 'text-boh-text-sub-light dark:text-boh-text-sub'}>{selected?.label || placeholder}</span><ChevronDown size={16} />
    </button>
    {open && <div role="listbox" className="absolute z-30 mt-1 max-h-64 w-full overflow-auto rounded-xl border border-boh-border-light bg-white p-1 shadow-xl dark:border-boh-border dark:bg-boh-surface">
      {options.map((option) => <button key={option.value} type="button" role="option" aria-selected={option.value === value} onClick={() => { onChange(option.value); setOpen(false); }} className="flex w-full items-start justify-between rounded-lg px-3 py-2 text-left hover:bg-boh-bg-light dark:hover:bg-boh-bg">
        <span><span className="block text-sm font-medium">{option.label}</span>{option.description && <span className="block text-xs text-boh-text-sub-light dark:text-boh-text-sub">{option.description}</span>}</span>{option.value === value && <Check size={16} className="mt-0.5 text-emerald-600" />}
      </button>)}
    </div>}
  </label>;
}

function PageHeader({ eyebrow, title, description, action }: { eyebrow: string; title: string; description: string; action?: React.ReactNode }) {
  return <header className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between">
    <div><p className="mb-1 text-xs font-semibold uppercase tracking-[0.16em] text-emerald-700 dark:text-emerald-300">{eyebrow}</p><h1 className="text-3xl font-semibold tracking-tight text-boh-text-light dark:text-boh-text">{title}</h1><p className="mt-1 max-w-2xl text-sm text-boh-text-sub-light dark:text-boh-text-sub">{description}</p></div>{action}
  </header>;
}

function EmptyState({ title, description, action }: { title: string; description: string; action?: React.ReactNode }) {
  return <div className={`${surface} flex min-h-64 flex-col items-center justify-center px-6 text-center`}><div className="mb-4 rounded-2xl bg-emerald-500/10 p-3 text-emerald-700 dark:text-emerald-300"><KeyRound size={24} /></div><h2 className="text-lg font-semibold">{title}</h2><p className="mt-1 max-w-md text-sm text-boh-text-sub-light dark:text-boh-text-sub">{description}</p>{action && <div className="mt-5">{action}</div>}</div>;
}

function NewItemDialog({ tenantId, initialEnvironment, accessEnvironments, adminEnvironments, projectOptions, onClose, onCreated }: { tenantId: string; initialEnvironment: VaultEnvironment; accessEnvironments: ReadonlySet<VaultEnvironment>; adminEnvironments: ReadonlySet<VaultEnvironment>; projectOptions: VaultProjectOption[]; onClose: () => void; onCreated: (id: string, environment: VaultEnvironment) => void }) {
  const [saving, setSaving] = useState(false);
  const [showProtectedValue, setShowProtectedValue] = useState(false);
  const [form, setForm] = useState(() => { const defaults = createVaultItemFormDefaults(initialEnvironment); const environment = accessEnvironments.has(defaults.environment) ? defaults.environment : [...accessEnvironments][0] || defaults.environment; return { ...defaults, environment, kind: adminEnvironments.has(environment) ? defaults.kind : 'password' as VaultItemKind }; });
  const save = async (event: React.FormEvent) => {
    event.preventDefault(); setSaving(true);
    try { const id = await createVaultItem(tenantId, form); toast.success('Vault item created'); onCreated(id, form.environment); }
    catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to create Vault item.'); }
    finally { setSaving(false); }
  };
  return <div className="fixed inset-0 z-50 flex flex-col justify-end bg-slate-950/45 sm:flex-row sm:items-stretch" role="dialog" aria-modal="true" aria-label="New Vault item"><button aria-label="Close" className="flex-1 cursor-default" onClick={onClose} /><form onSubmit={save} className="max-h-[88vh] w-full overflow-y-auto rounded-t-2xl bg-white p-6 shadow-2xl dark:bg-boh-surface sm:h-full sm:max-h-none sm:max-w-xl sm:rounded-none sm:p-8">
    <div className="mb-7 flex items-start justify-between"><div><p className="text-xs font-semibold uppercase tracking-[0.16em] text-emerald-700 dark:text-emerald-300">Vault item</p><h2 className="mt-1 text-2xl font-semibold">New Vault item</h2><p className="mt-1 text-sm text-boh-text-sub-light dark:text-boh-text-sub">Enter the item details and keep the protected value separate from searchable details.</p></div><button type="button" onClick={onClose} className={secondaryButton} aria-label="Close"><X size={17} /></button></div>
    <div className="space-y-5"><div role="tablist" aria-label="Vault item kind" className="flex border-b border-boh-border-light dark:border-boh-border">{adminEnvironments.has(form.environment) && <button type="button" role="tab" aria-selected={form.kind === 'api_secret'} onClick={() => setForm({ ...form, kind: 'api_secret' })} className={`border-b-2 px-3 py-2 text-sm font-medium ${form.kind === 'api_secret' ? 'border-emerald-600 text-emerald-700 dark:text-emerald-300' : 'border-transparent text-boh-text-sub-light dark:text-boh-text-sub'}`}>API key or secret</button>}<button type="button" role="tab" aria-selected={form.kind === 'password'} onClick={() => setForm({ ...form, kind: 'password' })} className={`border-b-2 px-3 py-2 text-sm font-medium ${form.kind === 'password' ? 'border-emerald-600 text-emerald-700 dark:text-emerald-300' : 'border-transparent text-boh-text-sub-light dark:text-boh-text-sub'}`}>Password</button></div>
      <fieldset><legend className="text-sm font-medium">Environment</legend><div className="mt-2 flex flex-wrap gap-x-6 gap-y-2">{(['development','production'] as VaultEnvironment[]).filter((environment) => accessEnvironments.has(environment)).map((environment) => <label key={environment} className="inline-flex cursor-pointer items-center gap-2 text-sm"><input type="radio" name="vault-item-environment" value={environment} checked={form.environment === environment} onChange={() => setForm({ ...form, environment, switchboardProjectId: '', kind: form.kind === 'api_secret' && !adminEnvironments.has(environment) ? 'password' : form.kind })} className="h-4 w-4 accent-emerald-600" />{friendly(environment)}</label>)}</div></fieldset>
      <label className="block text-sm font-medium">Name<input required autoFocus className={`${input} mt-1.5`} value={form.displayName} onChange={(e) => setForm({ ...form, displayName: e.target.value })} placeholder={form.kind === 'password' ? 'Application name' : 'Secret name'} /></label>
      {form.kind === 'password' ? <><label className="block text-sm font-medium">Website URL <span className="font-normal text-boh-text-sub-light dark:text-boh-text-sub">Optional</span><input className={`${input} mt-1.5`} value={form.websiteUrl} onChange={(e) => setForm({ ...form, websiteUrl: e.target.value })} placeholder="https://…" /></label><label className="block text-sm font-medium">Username <span className="font-normal text-boh-text-sub-light dark:text-boh-text-sub">Optional</span><input className={`${input} mt-1.5`} value={form.username} onChange={(e) => setForm({ ...form, username: e.target.value })} autoComplete="off" /></label></> : <><label className="block text-sm font-medium">Provider <span className="font-normal text-boh-text-sub-light dark:text-boh-text-sub">Optional</span><input className={`${input} mt-1.5`} value={form.providerKey} onChange={(e) => setForm({ ...form, providerKey: e.target.value })} placeholder={VAULT_PROVIDER_PLACEHOLDER} /></label><Picker label="Project" value={form.switchboardProjectId} onChange={(switchboardProjectId) => setForm({ ...form, switchboardProjectId })} placeholder="Choose a project" options={projectOptions.filter((project) => project.environment === form.environment).map((project) => ({ value: project.id, label: project.name, description: project.project_key }))} /><label className="block text-sm font-medium">Service URL <span className="font-normal text-boh-text-sub-light dark:text-boh-text-sub">Optional</span><input type="url" className={`${input} mt-1.5`} value={form.serviceUrl} onChange={(e) => setForm({ ...form, serviceUrl: e.target.value })} placeholder="https://…" /></label><label className="block text-sm font-medium">Purpose <span className="font-normal text-boh-text-sub-light dark:text-boh-text-sub">Optional</span><input className={`${input} mt-1.5`} value={form.purpose} onChange={(e) => setForm({ ...form, purpose: e.target.value })} placeholder="What this value enables" /></label><label className="block text-sm font-medium">Description <span className="font-normal text-boh-text-sub-light dark:text-boh-text-sub">Optional</span><textarea className={`${textarea} mt-1.5`} value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} placeholder="What this key is used for and which service depends on it." /></label><label className="block text-sm font-medium">Reference name<input required className={`${input} mt-1.5 font-mono uppercase`} value={form.referenceName} onChange={(e) => setForm({ ...form, referenceName: normalizeVaultReferenceName(e.target.value) })} /></label></>}
      <label className="block text-sm font-medium">{form.kind === 'password' ? 'Password' : 'Protected value'}<div className="mt-1.5 flex gap-2"><input {...getProtectedVaultValueInputProps(showProtectedValue)} className={input} value={form.protectedValue} onChange={(e) => setForm({ ...form, protectedValue: e.target.value })} /><button type="button" className={secondaryButton} onClick={() => setShowProtectedValue((current) => !current)} aria-label={showProtectedValue ? 'Hide protected value' : 'Show protected value'}>{showProtectedValue ? <EyeOff size={16} /> : <Eye size={16} />}{showProtectedValue ? 'Hide' : 'Show'}</button></div></label>
    </div><div className="mt-8 flex justify-end gap-3"><button type="button" className={secondaryButton} onClick={onClose}>Cancel</button><button disabled={saving || !form.displayName || !form.protectedValue || (form.kind === 'api_secret' && !form.referenceName)} className={primaryButton}>{saving ? 'Saving…' : 'Create item'}</button></div>
  </form></div>;
}

function ItemsPage({ tenantId, accessEnvironments, adminEnvironments }: { tenantId: string; accessEnvironments: ReadonlySet<VaultEnvironment>; adminEnvironments: ReadonlySet<VaultEnvironment> }) {
  const [items, setItems] = useState<VaultItem[]>([]); const [projectOptions, setProjectOptions] = useState<VaultProjectOption[]>([]); const [selectedItemId, setSelectedItemId] = useState<string | null>(null); const [category, setCategory] = useState<VaultCategory>('all'); const [environment, setEnvironment] = useState<VaultEnvironment>(() => [...accessEnvironments][0] || 'development'); const [projectFilter, setProjectFilter] = useState('all'); const [loading, setLoading] = useState(true); const [search, setSearch] = useState(''); const [showNew, setShowNew] = useState(false);
  const load = async () => { setLoading(true); try { const [nextItems, optionGroups] = await Promise.all([listVaultItems(tenantId), Promise.all([...accessEnvironments].map((itemEnvironment) => listVaultProjectOptions(tenantId, itemEnvironment).catch(() => [])))]); const nextProjectOptions = optionGroups.flat(); setItems(nextItems); setProjectOptions(nextProjectOptions); setSelectedItemId((current) => resolveVaultSelection(nextItems, current)); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to load items.'); } finally { setLoading(false); } };
  useEffect(() => { void load(); }, [tenantId]);
  const visible = useMemo(() => { const categoryItems = filterVaultItemsByCategory<VaultItem>(items, category); const environmentItems = filterVaultItemsByEnvironment<VaultItem>(categoryItems, environment); const projectNames = new Map(projectOptions.map((project) => [project.id, project.name])); return environmentItems.filter((item) => projectFilter === 'all' || item.switchboard_project_id === projectFilter).filter((item) => `${item.display_name} ${item.provider_key || ''} ${projectNames.get(item.switchboard_project_id || '') || ''} ${item.service_url || ''} ${item.description || ''} ${item.purpose || ''}`.toLowerCase().includes(search.toLowerCase())); }, [items, projectOptions, category, environment, projectFilter, search]);
  const chooseCategory = (nextCategory: VaultCategory) => { const categoryItems = filterVaultItemsByCategory<VaultItem>(items, nextCategory); const nextItems = filterVaultItemsByEnvironment<VaultItem>(categoryItems, environment); setCategory(nextCategory); setSelectedItemId((current) => resolveVaultSelection(nextItems, current)); };
  const chooseEnvironment = (nextEnvironment: VaultEnvironment) => { const nextCategory = category === 'api_secrets' && !adminEnvironments.has(nextEnvironment) ? 'all' : category; const categoryItems = filterVaultItemsByCategory<VaultItem>(items, nextCategory); const nextItems = filterVaultItemsByEnvironment<VaultItem>(categoryItems, nextEnvironment); setCategory(nextCategory); setEnvironment(nextEnvironment); setProjectFilter('all'); setSelectedItemId((current) => resolveVaultSelection(nextItems, current)); };
  return <><PageHeader eyebrow="Protected values" title="Vault" description="Store and manage passwords, service keys, certificates, and other sensitive information in one secure place." action={<button className={primaryButton} onClick={() => setShowNew(true)}><Plus size={16} />New item</button>} />
    <div role="tablist" aria-label="Vault categories" className="mb-2 flex border-b border-boh-border-light dark:border-boh-border">{([{ value: 'all', label: 'All items' }, { value: 'passwords', label: 'Passwords' }, { value: 'api_secrets', label: 'API keys & secrets' }] as const).filter((option) => option.value !== 'api_secrets' || adminEnvironments.has(environment)).map((option) => <button key={option.value} type="button" role="tab" aria-selected={category === option.value} onClick={() => chooseCategory(option.value)} className={`border-b-2 px-4 py-2.5 text-sm font-medium ${category === option.value ? 'border-emerald-600 text-emerald-700 dark:text-emerald-300' : 'border-transparent text-boh-text-sub-light hover:text-boh-text-light dark:text-boh-text-sub dark:hover:text-boh-text'}`}>{option.label}</button>)}</div>
    <div role="tablist" aria-label="Vault item environments" className="mb-5 flex border-b border-boh-border-light pl-2 dark:border-boh-border">{(['development','production'] as VaultEnvironment[]).filter((nextEnvironment) => accessEnvironments.has(nextEnvironment)).map((nextEnvironment) => <button key={nextEnvironment} type="button" role="tab" aria-selected={environment === nextEnvironment} onClick={() => chooseEnvironment(nextEnvironment)} className={`border-b-2 px-4 py-2 text-sm font-medium ${environment === nextEnvironment ? 'border-emerald-600 text-emerald-700 dark:text-emerald-300' : 'border-transparent text-boh-text-sub-light hover:text-boh-text-light dark:text-boh-text-sub dark:hover:text-boh-text'}`}>{friendly(nextEnvironment)} <span className="ml-1 text-xs opacity-70">{filterVaultItemsByEnvironment<VaultItem>(filterVaultItemsByCategory<VaultItem>(items, category), nextEnvironment).length}</span></button>)}</div>
    {projectOptions.some((project) => project.environment === environment) && <div className="mb-5 max-w-sm"><Picker label="Project" value={projectFilter} onChange={setProjectFilter} options={[{ value: 'all', label: 'All projects' }, ...projectOptions.filter((project) => project.environment === environment).map((project) => ({ value: project.id, label: project.name, description: project.project_key }))]} /></div>}
    {loading ? <div className={`${surface} p-8 text-sm text-boh-text-sub-light`}>Loading Vault…</div> : items.length === 0 ? <EmptyState title="No Vault items yet" description="Create the first Vault item for this company." action={<button className={primaryButton} onClick={() => setShowNew(true)}><Plus size={16} />New item</button>} /> : <div className="grid min-h-[34rem] gap-5 lg:grid-cols-[minmax(280px,360px)_minmax(0,1fr)]"><section className={`${surface} h-fit overflow-hidden`}><div className="border-b border-boh-border-light p-3 dark:border-boh-border"><label className="relative block"><Search size={16} className="absolute left-3 top-3 text-boh-text-sub-light" /><input className={`${input} pl-9`} value={search} onChange={(e) => setSearch(e.target.value)} placeholder="Search items" aria-label="Search Vault items" /></label><p className="mt-2 px-1 text-xs text-boh-text-sub-light dark:text-boh-text-sub">{visible.length} items</p></div>{visible.length === 0 ? <div className="p-6 text-sm text-boh-text-sub-light">No matching items.</div> : <div className="divide-y divide-boh-border-light dark:divide-boh-border">{visible.map((item) => <button key={item.id} onClick={() => setSelectedItemId(item.id)} aria-pressed={item.id === selectedItemId} className={`flex w-full items-start gap-3 px-4 py-4 text-left transition ${item.id === selectedItemId ? 'bg-emerald-500/10' : 'hover:bg-boh-bg-light dark:hover:bg-boh-bg'}`}><span className="rounded-xl bg-emerald-500/10 p-2.5 text-emerald-700 dark:text-emerald-300"><KeyRound size={18} /></span><span className="min-w-0 flex-1"><span className="block truncate font-semibold">{item.display_name}</span><span className="mt-0.5 block truncate text-sm text-boh-text-sub-light dark:text-boh-text-sub">{item.provider_key || friendly(item.item_type)}</span><span className="mt-2 flex items-center justify-between gap-2"><StatusBadge value={item.value_state} /><span className="text-xs text-boh-text-sub-light dark:text-boh-text-sub">{formatDate(item.updated_at)}</span></span></span></button>)}</div>}</section><section className="min-w-0">{selectedItemId ? <ItemDetailPanel tenantId={tenantId} itemId={selectedItemId} onChanged={load} /> : <EmptyState title="Select a Vault item" description="Choose an item from the list to view and manage it." />}</section></div>}
    {showNew && <NewItemDialog tenantId={tenantId} initialEnvironment={environment} accessEnvironments={accessEnvironments} adminEnvironments={adminEnvironments} projectOptions={projectOptions} onClose={() => setShowNew(false)} onCreated={(id, itemEnvironment) => { setShowNew(false); setEnvironment(itemEnvironment); setSelectedItemId(id); void load(); }} />}</>;
}

function ItemDetailPanel({ tenantId, itemId, onChanged }: { tenantId: string; itemId: string; onChanged: () => Promise<void> }) {
  const [item, setItem] = useState<VaultItem | null>(null); const [projectOptions, setProjectOptions] = useState<VaultProjectOption[]>([]); const [fields, setFields] = useState<VaultField[]>([]); const [activity, setActivity] = useState<VaultAuditEvent[]>([]); const [connectedFieldIds, setConnectedFieldIds] = useState<Set<string>>(new Set()); const [revealed, setRevealed] = useState<Record<string,string>>({}); const [editing, setEditing] = useState<string | null>(null); const [nextValue, setNextValue] = useState(''); const [editingDetails, setEditingDetails] = useState(false); const [savingDetails, setSavingDetails] = useState(false); const [detailForm, setDetailForm] = useState({ displayName: '', providerKey: '', projectWorkspace: '', projectId: '', switchboardProjectId: '', serviceUrl: '', purpose: '', description: '', referenceName: '' }); const [confirmingDelete, setConfirmingDelete] = useState(false); const [deleting, setDeleting] = useState(false);
  const load = async () => { try { const [items, nextFields, sync, nextActivity] = await Promise.all([listVaultItems(tenantId), listVaultFields(tenantId, itemId), listVaultSync(tenantId), listVaultActivity(tenantId, itemId)]); const selectedItem = items.find((candidate) => candidate.id === itemId) || null; setItem(selectedItem); setProjectOptions(selectedItem ? await listVaultProjectOptions(tenantId, selectedItem.environment).catch(() => []) : []); setFields(nextFields); setActivity(nextActivity); setConnectedFieldIds(new Set(sync.bindings.filter((binding) => binding.vault_item_id === itemId && binding.state !== 'disabled').map((binding) => binding.item_field_id))); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to load item.'); } };
  useEffect(() => { void load(); return () => setRevealed({}); }, [tenantId, itemId]);
  useEffect(() => { if (!Object.keys(revealed).length) return; const timer = window.setTimeout(() => setRevealed({}), 30_000); return () => window.clearTimeout(timer); }, [revealed]);
  if (!item) return <div className={`${surface} p-8 text-sm text-boh-text-sub-light`}>Loading item…</div>;
  const reveal = async (field: VaultField) => { try { const value = await readVaultValue(tenantId, item.id, field.id, 'reveal', item.environment); setRevealed((current) => ({ ...current, [field.id]: value })); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to reveal value.'); } };
  const copy = async (field: VaultField) => { try { const value = await readVaultValue(tenantId, item.id, field.id, 'copy', item.environment); await navigator.clipboard.writeText(value); toast.success('Copied to clipboard'); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to copy value.'); } };
  const replace = async (field: VaultField) => { try { await setVaultValue(tenantId, item.id, field.id, nextValue, item.environment); setEditing(null); setNextValue(''); setRevealed({}); toast.success('Protected value updated'); await Promise.all([load(), onChanged()]); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to update value.'); } };
  const remove = async () => { setDeleting(true); try { await deleteVaultItem(tenantId, item.id, item.environment); setRevealed({}); setConfirmingDelete(false); toast.success('Vault item deleted'); await onChanged(); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to delete item.'); } finally { setDeleting(false); } };
  const protectedField = fields.find((field) => field.field_kind === 'protected') ?? null;
  const selectedProjectName = projectOptions.find((project) => project.id === item.switchboard_project_id)?.name;
  const beginDetailsEdit = () => { setDetailForm({ displayName: item.display_name, providerKey: item.provider_key || '', projectWorkspace: item.project_workspace || '', projectId: item.project_id || '', switchboardProjectId: item.switchboard_project_id || '', serviceUrl: item.service_url || '', purpose: item.purpose || '', description: item.description || '', referenceName: protectedField?.field_key || '' }); setEditingDetails(true); };
  const saveDetails = async () => { setSavingDetails(true); try { await updateVaultItemDetails(tenantId, { itemId: item.id, displayName: detailForm.displayName, providerKey: detailForm.providerKey, projectWorkspace: detailForm.projectWorkspace, projectId: detailForm.projectId, switchboardProjectId: detailForm.switchboardProjectId, serviceUrl: detailForm.serviceUrl, purpose: detailForm.purpose, description: detailForm.description, protectedFieldId: item.item_type === 'login' ? null : protectedField?.id || null, referenceName: item.item_type === 'login' ? null : detailForm.referenceName, environment: item.environment }); toast.success('Vault item updated'); setEditingDetails(false); await Promise.all([load(), onChanged()]); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to update Vault item.'); } finally { setSavingDetails(false); } };
  return <><PageHeader eyebrow={item.provider_key || friendly(item.item_type)} title={item.display_name} description={item.item_type === 'login' ? 'Password' : 'API key or secret'} action={<div className="flex items-center gap-2"><StatusBadge value={item.value_state} /><button type="button" className={secondaryButton} onClick={beginDetailsEdit}><Pencil size={15} />Edit</button><button type="button" className="inline-flex h-9 items-center justify-center gap-2 rounded-lg border border-red-200 bg-white px-3 text-sm font-medium text-red-700 transition hover:bg-red-50 dark:border-red-900/60 dark:bg-boh-bg dark:text-red-300 dark:hover:bg-red-950/30" onClick={() => setConfirmingDelete(true)}><Trash2 size={15} />Delete</button></div>} />
    <div className="flex flex-col"><section className={`${surface} order-2 overflow-hidden rounded-t-none`}><div className="divide-y divide-boh-border-light dark:divide-boh-border">{fields.map((field) => <div key={field.id} className="px-5 py-4"><div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between"><div><div className="flex items-center gap-2"><span className="font-medium">{field.label}</span></div>{field.field_kind === 'protected' && item.item_type !== 'login' && <div className="mt-1 font-mono text-xs text-boh-text-sub-light dark:text-boh-text-sub">{field.field_key}</div>}<div className="mt-1 font-mono text-sm text-boh-text-sub-light dark:text-boh-text-sub">{field.field_kind === 'plaintext' && field.field_key === 'website_url' && field.plaintext_value ? <a className="font-sans font-medium text-emerald-700 hover:underline dark:text-emerald-300" href={field.plaintext_value} target="_blank" rel="noreferrer">Open website</a> : field.field_kind === 'plaintext' ? field.plaintext_value || 'Not set' : revealed[field.id] || '••••••••••••••••'}</div></div>{field.field_kind === 'protected' && <div className="flex flex-wrap gap-2"><button className={secondaryButton} onClick={() => revealed[field.id] ? setRevealed((current) => { const next = { ...current }; delete next[field.id]; return next; }) : reveal(field)}>{revealed[field.id] ? <EyeOff size={15} /> : <Eye size={15} />}{revealed[field.id] ? 'Hide' : 'Reveal'}</button><button className={secondaryButton} onClick={() => copy(field)}><Copy size={15} />Copy</button><button className={secondaryButton} onClick={() => setEditing(field.id)}><RefreshCw size={15} />Replace</button></div>}</div>{editing === field.id && <div className="mt-4 flex flex-col gap-2 rounded-xl bg-boh-bg-light p-3 dark:bg-boh-bg sm:flex-row"><input {...getProtectedVaultValueInputProps(false)} autoFocus className={input} value={nextValue} onChange={(e) => setNextValue(e.target.value)} placeholder="New protected value" /><button className={primaryButton} disabled={!nextValue} onClick={() => replace(field)}>Save</button><button className={secondaryButton} onClick={() => { setEditing(null); setNextValue(''); }}>Cancel</button></div>}</div>)}</div></section>
      <aside className="contents"><section className={`${surface} order-1 rounded-b-none border-b-0 p-5`}><dl className="grid gap-4 text-sm sm:grid-cols-2 xl:grid-cols-3"><div><dt className="text-boh-text-sub-light dark:text-boh-text-sub">Environment</dt><dd className="mt-0.5 font-medium">{friendly(item.environment)}</dd></div>{item.switchboard_project_id && <div><dt className="text-boh-text-sub-light dark:text-boh-text-sub">Project</dt><dd className="mt-0.5 font-medium">{selectedProjectName || 'Linked Switchboard project'}</dd></div>}{item.service_url && <div><dt className="text-boh-text-sub-light dark:text-boh-text-sub">Service URL</dt><dd className="mt-0.5"><a className="font-medium text-emerald-700 hover:underline dark:text-emerald-300" href={item.service_url} target="_blank" rel="noreferrer">Open service</a></dd></div>}{item.purpose && <div><dt className="text-boh-text-sub-light dark:text-boh-text-sub">Purpose</dt><dd className="mt-0.5 font-medium">{item.purpose}</dd></div>}<div><dt className="text-boh-text-sub-light dark:text-boh-text-sub">Validation</dt><dd className="mt-0.5"><StatusBadge value={item.validation_state} /></dd></div><div><dt className="text-boh-text-sub-light dark:text-boh-text-sub">Last rotated</dt><dd className="mt-0.5 font-medium">{formatDate(item.last_rotated_at)}</dd></div></dl></section>{(item.description || item.notes) && <section className={`${surface} order-3 mt-5 p-5`}><h2 className="font-semibold">Notes</h2>{item.description && <p className="mt-3 text-sm">{item.description}</p>}{item.notes && <p className="mt-3 whitespace-pre-wrap text-sm text-boh-text-sub-light dark:text-boh-text-sub">{item.notes}</p>}</section>}<section className={`${surface} order-4 mt-5 overflow-hidden`}><div className="border-b border-boh-border-light px-5 py-4 dark:border-boh-border"><h2 className="font-semibold">Recent activity</h2></div>{activity.length === 0 ? <p className="p-5 text-sm text-boh-text-sub-light dark:text-boh-text-sub">No recent activity.</p> : <div className="divide-y divide-boh-border-light dark:divide-boh-border">{activity.map((event) => <div key={event.id} className="flex items-center justify-between gap-4 px-5 py-3 text-sm"><span>{friendly(event.event_type)}</span><time className="whitespace-nowrap text-xs text-boh-text-sub-light dark:text-boh-text-sub">{formatDate(event.created_at)}</time></div>)}</div>}</section></aside></div>{editingDetails && <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-950/45 p-4" role="dialog" aria-modal="true" aria-labelledby="edit-vault-item-title"><div className={`${surface} max-h-[90vh] w-full max-w-xl overflow-y-auto p-6`}><div className="flex items-start justify-between gap-4"><div><h2 id="edit-vault-item-title" className="text-lg font-semibold">Edit Vault item</h2><p className="mt-1 text-sm text-boh-text-sub-light dark:text-boh-text-sub">Environment remains {friendly(item.environment)} to preserve its security history.</p></div><button type="button" className={secondaryButton} onClick={()=>setEditingDetails(false)} aria-label="Close"><X size={16}/></button></div><div className="mt-5 space-y-4"><label className="block text-sm font-medium">Name<input autoFocus className={`${input} mt-1.5`} value={detailForm.displayName} onChange={(e)=>setDetailForm({...detailForm,displayName:e.target.value})}/></label>{item.item_type !== 'login' && <><label className="block text-sm font-medium">Provider <span className="font-normal text-boh-text-sub-light dark:text-boh-text-sub">Optional</span><input className={`${input} mt-1.5`} value={detailForm.providerKey} onChange={(e)=>setDetailForm({...detailForm,providerKey:e.target.value})}/></label><Picker label="Project" value={detailForm.switchboardProjectId} onChange={(switchboardProjectId)=>setDetailForm({...detailForm,switchboardProjectId})} placeholder="Choose a project" options={projectOptions.map((project)=>({value:project.id,label:project.name,description:project.project_key}))}/><label className="block text-sm font-medium">Service URL <span className="font-normal text-boh-text-sub-light dark:text-boh-text-sub">Optional</span><input type="url" className={`${input} mt-1.5`} value={detailForm.serviceUrl} onChange={(e)=>setDetailForm({...detailForm,serviceUrl:e.target.value})} placeholder="https://…" /></label><label className="block text-sm font-medium">Purpose <span className="font-normal text-boh-text-sub-light dark:text-boh-text-sub">Optional</span><input className={`${input} mt-1.5`} value={detailForm.purpose} onChange={(e)=>setDetailForm({...detailForm,purpose:e.target.value})} placeholder="What this value enables" /></label><label className="block text-sm font-medium">Description <span className="font-normal text-boh-text-sub-light dark:text-boh-text-sub">Optional</span><textarea className={`${textarea} mt-1.5`} value={detailForm.description} onChange={(e)=>setDetailForm({...detailForm,description:e.target.value})} placeholder="What this key is used for and which service depends on it." /></label><label className="block text-sm font-medium">Reference name<input disabled={Boolean(protectedField && connectedFieldIds.has(protectedField.id))} className={`${input} mt-1.5 font-mono uppercase disabled:cursor-not-allowed disabled:opacity-60`} value={detailForm.referenceName} onChange={(e)=>setDetailForm({...detailForm,referenceName:normalizeVaultReferenceName(e.target.value)})}/>{protectedField && connectedFieldIds.has(protectedField.id) && <span className="mt-1.5 block text-xs font-normal text-boh-text-sub-light dark:text-boh-text-sub">Remove the active connections before changing this reference.</span>}</label></>}</div><div className="mt-6 flex justify-end gap-2"><button type="button" className={secondaryButton} disabled={savingDetails} onClick={()=>setEditingDetails(false)}>Cancel</button><button type="button" className={primaryButton} disabled={savingDetails||!detailForm.displayName||(item.item_type!=='login'&&!detailForm.referenceName)} onClick={()=>void saveDetails()}>{savingDetails?'Saving…':'Save changes'}</button></div></div></div>}{confirmingDelete && <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-950/45 p-4" role="dialog" aria-modal="true" aria-labelledby="delete-vault-item-title"><div className={`${surface} w-full max-w-md p-6`}><div className="flex items-start gap-3"><span className="rounded-xl bg-red-500/10 p-2.5 text-red-700 dark:text-red-300"><Trash2 size={20} /></span><div><h2 id="delete-vault-item-title" className="text-lg font-semibold">Delete {item.display_name}?</h2><p className="mt-1 text-sm text-boh-text-sub-light dark:text-boh-text-sub">This removes the item from Vault and disables its synchronization. Its security history is retained.</p></div></div><div className="mt-6 flex justify-end gap-2"><button type="button" className={secondaryButton} disabled={deleting} onClick={() => setConfirmingDelete(false)}>Cancel</button><button type="button" className="inline-flex h-9 items-center justify-center gap-2 rounded-lg bg-red-600 px-3 text-sm font-semibold text-white transition hover:bg-red-700 disabled:cursor-not-allowed disabled:opacity-50" disabled={deleting} onClick={() => void remove()}>{deleting ? 'Deleting…' : 'Delete'}</button></div></div></div>}</>;
}

function AccessPage({ tenantId, adminEnvironments }: { tenantId: string; adminEnvironments: ReadonlySet<VaultEnvironment> }) {
  const allowedEnvironments = (['development', 'production'] as VaultEnvironment[]).filter((environment) => adminEnvironments.has(environment));
  const [grants, setGrants] = useState<VaultGrant[]>([]); const [users, setUsers] = useState<BohUserOption[]>([]); const [userId, setUserId] = useState(''); const [role, setRole] = useState('vault_viewer'); const [grantEnvironment, setGrantEnvironment] = useState<VaultEnvironment>(allowedEnvironments[0] || 'development'); const [saving, setSaving] = useState(false);
  const load = async () => { try { const [nextGrants, nextUsers] = await Promise.all([listVaultAccess(tenantId), listBohUsers(tenantId)]); setGrants(nextGrants); setUsers(nextUsers); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to load access.'); } };
  useEffect(() => { void load(); }, [tenantId]);
  const save = async () => { setSaving(true); try { await saveVaultGrant(tenantId, { bohUserId: userId, role, status: 'active', environment: grantEnvironment }); toast.success('Vault access added'); setUserId(''); await load(); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to update access.'); } finally { setSaving(false); } };
  const names = new Map(users.map((user) => [user.id, user.full_name || user.email || 'BOH user']));
  return <><PageHeader eyebrow="Administration" title="Access" description="Control who can manage passwords and protected operational values." /><div className="grid gap-5 xl:grid-cols-[minmax(0,1fr)_360px]"><section className={`${surface} overflow-hidden`}><div className="border-b border-boh-border-light px-5 py-4 dark:border-boh-border"><h2 className="font-semibold">Current access</h2></div>{grants.length === 0 ? <div className="p-8 text-sm text-boh-text-sub-light">No grants are visible.</div> : <div className="divide-y divide-boh-border-light dark:divide-boh-border">{grants.map((grant) => <div key={grant.id} className="grid gap-2 px-5 py-4 sm:grid-cols-[minmax(0,1fr)_150px_100px] sm:items-center"><div><p className="font-medium">{names.get(grant.boh_user_id) || 'BOH user'}</p><p className="text-xs text-boh-text-sub-light dark:text-boh-text-sub">{friendly(grant.environment)}</p></div><span className="text-sm">{friendly(grant.role)}</span><StatusBadge value={grant.status} /></div>)}</div>}</section><section className={`${surface} h-fit p-5`}><h2 className="font-semibold">Add access</h2><div className="mt-4 space-y-4"><Picker label="Environment" value={grantEnvironment} onChange={(value) => setGrantEnvironment(value as VaultEnvironment)} options={allowedEnvironments.map((environment) => ({ value: environment, label: friendly(environment) }))} /><Picker label="Team member" value={userId} onChange={setUserId} options={users.map((user) => ({ value: user.id, label: user.full_name || user.email || 'BOH user', description: user.email || undefined }))} /><Picker label="Access level" value={role} onChange={setRole} options={[{value:'vault_viewer',label:'Personal passwords',description:'Create and manage only their own passwords'},{value:'vault_admin',label:'Administrator',description:'Manage operational values, access, and destinations'}]} /><button disabled={!userId || saving} className={`${primaryButton} w-full`} onClick={save}>{saving ? 'Adding…' : 'Add access'}</button></div></section></div></>;
}

function SyncPage({ tenantId, adminEnvironments }: { tenantId: string; adminEnvironments: ReadonlySet<VaultEnvironment> }) {
  const allowedEnvironments = (['development', 'production'] as VaultEnvironment[]).filter((environment) => adminEnvironments.has(environment));
  const [syncEnvironment, setSyncEnvironment] = useState<VaultEnvironment>(allowedEnvironments[0] || 'development');
  const [items, setItems] = useState<VaultItem[]>([]); const [fields, setFields] = useState<VaultField[]>([]); const [adapters, setAdapters] = useState<VaultAdapter[]>([]); const [targets, setTargets] = useState<VaultTarget[]>([]); const [bindings, setBindings] = useState<VaultBinding[]>([]); const [runs, setRuns] = useState<VaultRun[]>([]); const [selectedBindingId, setSelectedBindingId] = useState<string | null>(null); const [removingBindingId, setRemovingBindingId] = useState<string | null>(null); const [showTarget, setShowTarget] = useState(false); const [showBinding, setShowBinding] = useState(false); const [targetForm, setTargetForm] = useState({ adapterId: '', displayName: '', targetKey: '', targetUrl: '' }); const [bindingForm, setBindingForm] = useState({ fieldId: '', targetId: '', destinationKey: '' });
  const load = async () => { try { const [nextItems, sync] = await Promise.all([listVaultItems(tenantId), listVaultSync(tenantId)]); const syncableItems = filterVaultItemsForSynchronization(nextItems); const nextFields = (await Promise.all(syncableItems.map((item) => listVaultFields(tenantId, item.id)))).flat(); const activeBindings = filterActiveVaultBindings(sync.bindings); setItems(syncableItems); setFields(nextFields); setAdapters(sync.adapters); setTargets(sync.targets); setBindings(activeBindings); setRuns(sync.runs); setSelectedBindingId((current) => resolveVaultSelection(activeBindings, current)); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to load synchronization.'); } };
  useEffect(() => { void load(); }, [tenantId]);
  const itemNames = new Map<string, string>(items.map((item): [string, string] => [item.id, item.display_name])); const fieldById = new Map<string, VaultField>(fields.map((field): [string, VaultField] => [field.id, field])); const targetNames = new Map<string, string>(targets.map((target): [string, string] => [target.id, target.display_name]));
  const environmentItems = filterVaultRecordsByEnvironment<VaultItem>(items, syncEnvironment);
  const environmentItemIds = new Set(environmentItems.map((item) => item.id));
  const environmentFields = fields.filter((field) => environmentItemIds.has(field.vault_item_id));
  const environmentTargets = filterVaultRecordsByEnvironment<VaultTarget>(targets, syncEnvironment);
  const environmentBindings = filterVaultRecordsByEnvironment<VaultBinding>(bindings, syncEnvironment);
  const selectedTargetAdapter = adapters.find((adapter) => adapter.id === targetForm.adapterId);
  const targetReferenceLabel = selectedTargetAdapter?.adapter_key === 'supabase_edge_secrets'
    ? 'Supabase project reference'
    : selectedTargetAdapter?.adapter_key === 'cloudflare_worker_secrets'
      ? 'Cloudflare account ID / Worker name'
      : 'HTTPS target';
  const targetReferencePlaceholder = selectedTargetAdapter?.adapter_key === 'supabase_edge_secrets'
    ? 'project-ref'
    : selectedTargetAdapter?.adapter_key === 'cloudflare_worker_secrets'
      ? 'account-id/worker-name'
      : 'https://…';
  const resolvedSelectedBindingId = resolveVaultSelection(environmentBindings, selectedBindingId);
  const selectedBinding = environmentBindings.find((binding) => binding.id === resolvedSelectedBindingId) ?? null;
  const selectedField = selectedBinding ? fieldById.get(selectedBinding.item_field_id) : undefined;
  const selectedRuns = filterVaultRunsByBinding<VaultRun>(runs, selectedBinding?.id ?? null).slice(0, 10);
  const addTarget = async () => { try { await createVaultTarget(tenantId, { ...targetForm, environment: syncEnvironment }); toast.success('Destination added'); setShowTarget(false); setTargetForm({ adapterId: '', displayName: '', targetKey: '', targetUrl: '' }); await load(); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to add destination.'); } };
  const addBinding = async () => { const field = fieldById.get(bindingForm.fieldId); if (!field) return; try { await createVaultBinding(tenantId, { itemId: field.vault_item_id, fieldId: field.id, targetId: bindingForm.targetId, destinationKey: bindingForm.destinationKey, environment: syncEnvironment }); toast.success('Connection added'); setShowBinding(false); setBindingForm({ fieldId: '', targetId: '', destinationKey: '' }); await load(); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to add connection.'); } };
  const run = async (binding: VaultBinding) => { try { await runVaultSync(tenantId, binding.id, binding.environment); toast.success('Synchronization completed'); await load(); } catch (error) { toast.error(error instanceof Error ? error.message : 'Synchronization failed.'); await load(); } };
  const removeBinding = async (binding: VaultBinding) => { try { await removeVaultBinding(tenantId, binding.id, binding.environment); toast.success('Connection removed'); setRemovingBindingId(null); await load(); } catch (error) { toast.error(error instanceof Error ? error.message : 'Unable to remove connection.'); } };
  const chooseSyncEnvironment = (environment: VaultEnvironment) => { setSyncEnvironment(environment); setSelectedBindingId(resolveVaultSelection(filterVaultRecordsByEnvironment<VaultBinding>(bindings, environment), null)); setShowTarget(false); setShowBinding(false); };
  return <><PageHeader eyebrow="Delivery" title="Synchronization" description="Send approved Vault values through environment-matched connections." action={<div className="flex gap-2"><button className={secondaryButton} onClick={() => { setShowTarget(!showTarget); setShowBinding(false); }}><Database size={16} />Destination</button><button className={primaryButton} onClick={() => { setShowBinding(!showBinding); setShowTarget(false); }}><Link2 size={16} />Connection</button></div>} />
    <div role="tablist" aria-label="Synchronization environments" className="mb-5 flex border-b border-boh-border-light dark:border-boh-border">{allowedEnvironments.map((option) => <button key={option} type="button" role="tab" aria-selected={syncEnvironment === option} onClick={() => chooseSyncEnvironment(option)} className={`border-b-2 px-4 py-2 text-sm font-medium ${syncEnvironment === option ? 'border-emerald-600 text-emerald-700 dark:text-emerald-300' : 'border-transparent text-boh-text-sub-light dark:text-boh-text-sub'}`}>{friendly(option)}</button>)}</div>
    <p className="mb-5 text-sm text-boh-text-sub-light dark:text-boh-text-sub">Only {friendly(syncEnvironment)} items, destinations, and connections are shown.</p>
    {(showTarget || showBinding) && <section className={`${surface} mb-5 p-5`}><div className="grid gap-4 lg:grid-cols-4">{showTarget ? <><Picker label="Target type" value={targetForm.adapterId} onChange={(adapterId) => setTargetForm({...targetForm,adapterId})} options={adapters.map((adapter) => ({value:adapter.id,label:adapter.display_name,description:adapter.description || adapter.adapter_version}))} /><label className="text-sm font-medium">Name<input className={`${input} mt-1.5`} value={targetForm.displayName} onChange={(e)=>setTargetForm({...targetForm,displayName:e.target.value})} /></label><label className="text-sm font-medium">Reference<input className={`${input} mt-1.5`} value={targetForm.targetKey} onChange={(e)=>setTargetForm({...targetForm,targetKey:e.target.value.toLowerCase().replace(/[^a-z0-9_-]/g,'-')})} /></label><label className="text-sm font-medium">{targetReferenceLabel}<input className={`${input} mt-1.5`} value={targetForm.targetUrl} onChange={(e)=>setTargetForm({...targetForm,targetUrl:e.target.value})} placeholder={targetReferencePlaceholder} /></label><button className={primaryButton} disabled={!targetForm.adapterId||!targetForm.displayName||!targetForm.targetKey||!targetForm.targetUrl} onClick={addTarget}>Save target</button></> : <><Picker label="Vault value" value={bindingForm.fieldId} onChange={(fieldId)=>setBindingForm({...bindingForm,fieldId})} options={environmentFields.filter((field)=>field.field_kind==='protected').map((field)=>({value:field.id,label:`${itemNames.get(field.vault_item_id) || 'Item'} · ${field.label}`}))} /><Picker label="Sends to" value={bindingForm.targetId} onChange={(targetId)=>setBindingForm({...bindingForm,targetId})} options={environmentTargets.filter((target)=>target.status==='active').map((target)=>({value:target.id,label:target.display_name,description:target.adapter_name}))} /><label className="text-sm font-medium">Secret name<input className={`${input} mt-1.5`} value={bindingForm.destinationKey} onChange={(e)=>setBindingForm({...bindingForm,destinationKey:e.target.value})} placeholder="SECRET_NAME" /></label><div className="flex items-end"><button className={`${primaryButton} w-full`} disabled={!bindingForm.fieldId||!bindingForm.targetId||!bindingForm.destinationKey} onClick={addBinding}>Save connection</button></div></>}</div></section>}
    <div className="grid min-h-[32rem] gap-5 md:grid-cols-[minmax(280px,0.8fr)_minmax(0,1.6fr)]"><section className={`${surface} overflow-hidden`}><div className="flex items-center justify-between border-b border-boh-border-light px-5 py-4 dark:border-boh-border"><h2 className="font-semibold">Connections</h2><span className="text-xs text-boh-text-sub-light dark:text-boh-text-sub">{environmentBindings.length}</span></div>{environmentBindings.length===0?<div className="p-8 text-sm text-boh-text-sub-light">No connections yet.</div>:<div role="listbox" aria-label="Connections" className="max-h-[calc(100vh-18rem)] min-h-80 divide-y divide-boh-border-light overflow-y-auto dark:divide-boh-border">{environmentBindings.map((binding)=>{const selected=binding.id===selectedBinding?.id;const display=getVaultConnectionDisplay(itemNames.get(binding.vault_item_id)||'Vault item',targetNames.get(binding.deployment_target_id)||'Destination',binding.destination_key);return <button key={binding.id} type="button" role="option" aria-selected={selected} onClick={()=>setSelectedBindingId(binding.id)} className={`flex w-full items-center justify-between gap-3 px-5 py-4 text-left transition ${selected?'bg-emerald-500/5 ring-1 ring-inset ring-emerald-500/20':'hover:bg-boh-bg-light dark:hover:bg-boh-bg'}`}><div className="min-w-0"><p className="truncate font-medium">{display.title}</p><p className="truncate text-xs text-boh-text-sub-light dark:text-boh-text-sub">→ {display.destination}</p><p className="truncate font-mono text-[11px] text-boh-text-sub-light dark:text-boh-text-sub">{display.secretName}</p></div><StatusBadge value={getVaultSyncDisplayStatus(binding)}/></button>})}</div>}</section><section className={`${surface} overflow-hidden`}>{!selectedBinding?<div className="flex min-h-80 items-center justify-center p-8 text-sm text-boh-text-sub-light">Select a connection to view it.</div>:<><div className="flex flex-col gap-4 border-b border-boh-border-light px-5 py-5 sm:flex-row sm:items-start sm:justify-between dark:border-boh-border"><div className="min-w-0"><div className="flex flex-wrap items-center gap-2"><h2 className="truncate text-lg font-semibold">{itemNames.get(selectedBinding.vault_item_id)||'Vault item'} · {selectedField?.label||selectedBinding.destination_key}</h2><StatusBadge value={getVaultSyncDisplayStatus(selectedBinding)}/></div><p className="mt-1 text-sm text-boh-text-sub-light dark:text-boh-text-sub">{targetNames.get(selectedBinding.deployment_target_id)||'Target'} · {selectedBinding.destination_key}</p></div><div className="flex shrink-0 items-center gap-2">{removingBindingId===selectedBinding.id?<><button className={secondaryButton} onClick={()=>setRemovingBindingId(null)}>Cancel</button><button className="inline-flex h-9 items-center justify-center gap-2 rounded-lg border border-red-500/30 bg-red-500/10 px-3 text-sm font-medium text-red-700 transition hover:bg-red-500/15 dark:text-red-300" onClick={()=>removeBinding(selectedBinding)}><Trash2 size={15}/>Confirm remove</button></>:<><button className={secondaryButton} onClick={()=>setRemovingBindingId(selectedBinding.id)}><Trash2 size={15}/>Remove</button><button className={secondaryButton} disabled={selectedBinding.state!=='ready'} onClick={()=>run(selectedBinding)}><RefreshCw size={15}/>Sync</button></>}</div></div><dl className="grid gap-4 border-b border-boh-border-light px-5 py-4 text-sm sm:grid-cols-3 dark:border-boh-border"><div><dt className="text-boh-text-sub-light dark:text-boh-text-sub">Environment</dt><dd className="mt-0.5 font-medium">{friendly(selectedBinding.environment)}</dd></div><div><dt className="text-boh-text-sub-light dark:text-boh-text-sub">Last synced</dt><dd className="mt-0.5 font-medium">{formatDate(selectedBinding.last_synced_at)}</dd></div><div><dt className="text-boh-text-sub-light dark:text-boh-text-sub">Sends to</dt><dd className="mt-0.5 truncate font-medium">{targetNames.get(selectedBinding.deployment_target_id)||'Target'}</dd></div></dl><div className="border-b border-boh-border-light px-5 py-4 dark:border-boh-border"><h3 className="font-semibold">Recent runs</h3></div>{selectedRuns.length===0?<div className="p-8 text-sm text-boh-text-sub-light">No runs for this connection yet.</div>:<div className="max-h-80 divide-y divide-boh-border-light overflow-y-auto dark:divide-boh-border">{selectedRuns.map((syncRun)=><div key={syncRun.id} className="grid grid-cols-[minmax(0,1fr)_100px] items-center gap-3 px-5 py-4"><div><p className="text-sm font-medium">Attempt {syncRun.attempt}</p><p className="text-xs text-boh-text-sub-light dark:text-boh-text-sub">{formatDate(syncRun.created_at)}{syncRun.result_code?` · ${friendly(syncRun.result_code)}`:''}</p></div><StatusBadge value={syncRun.status}/></div>)}</div>}</>}</section></div></>;
}

const VaultApp: React.FC<{ isAdmin?: boolean }> = ({ isAdmin = false }) => {
  const access = useBohAccess(); const tenantId = access.bohUser?.tenant_id; const bohUserId = access.bohUser?.id;
  const [ownGrants, setOwnGrants] = useState<VaultGrant[]>([]); const [grantsLoading, setGrantsLoading] = useState(true);
  useEffect(() => {
    let active = true;
    if (!tenantId || !bohUserId) { setOwnGrants([]); setGrantsLoading(false); return () => { active = false; }; }
    setGrantsLoading(true);
    void listVaultAccess(tenantId).then((grants) => {
      if (active) setOwnGrants(grants.filter((grant) => grant.boh_user_id === bohUserId));
    }).catch(() => { if (active) setOwnGrants([]); }).finally(() => { if (active) setGrantsLoading(false); });
    return () => { active = false; };
  }, [tenantId, bohUserId]);
  const activeGrants = ownGrants.filter((grant) => ['vault_admin', 'vault_editor', 'vault_viewer'].includes(grant.role) && grant.status === 'active' && (!grant.expires_at || new Date(grant.expires_at).getTime() > Date.now()));
  const accessEnvironments = new Set<VaultEnvironment>(activeGrants.map((grant) => grant.environment));
  const adminEnvironments = new Set<VaultEnvironment>(activeGrants.filter((grant) => grant.role === 'vault_admin').map((grant) => grant.environment));
  const canAdmin = adminEnvironments.size > 0;
  const scopedApps = useMemo(() => bohApps.map((app) => app.id !== 'vault' || !app.navConfig ? app : ({ ...app, navConfig: { ...app.navConfig, sidebarItems: app.navConfig.sidebarItems.filter((item) => canAdmin || ('key' in item && item.key === 'items')) } })), [canAdmin]);
  if (access.isLoading || grantsLoading) return <BOHShell apps={scopedApps} isAdmin={isAdmin}><div className={`${surface} p-8 text-sm text-boh-text-sub-light`}>Loading Vault access…</div></BOHShell>;
  if (!tenantId || !bohUserId) return <BOHShell apps={scopedApps} isAdmin={isAdmin}><EmptyState title="Vault unavailable" description={access.error || 'Your BOH profile is not connected to a company.'}/></BOHShell>;
  if (activeGrants.length === 0) return <BOHShell apps={scopedApps} isAdmin={isAdmin}><EmptyState title="Vault unavailable" description="You do not have active Vault access for this company."/></BOHShell>;
  return <BOHShell apps={scopedApps} isAdmin={isAdmin || access.isSuperAdmin}><Routes><Route path="/" element={<ItemsPage tenantId={tenantId} accessEnvironments={accessEnvironments} adminEnvironments={adminEnvironments}/>} /><Route path="sync" element={canAdmin ? <SyncPage tenantId={tenantId} adminEnvironments={adminEnvironments}/> : <Navigate to="/vault" replace/>} /><Route path="access" element={canAdmin ? <AccessPage tenantId={tenantId} adminEnvironments={adminEnvironments}/> : <Navigate to="/vault" replace/>} /><Route path="activity" element={<Navigate to="/vault" replace/>} /><Route path="*" element={<Navigate to="/vault" replace/>}/></Routes></BOHShell>;
};

export default VaultApp;
